njs_unit_test(njs_unit_test_t tests[], size_t num, njs_str_t *name,
    njs_opts_t *opts, njs_stat_t *stat)
{
    u_char                *start, *end;
    njs_vm_t              *vm;
    njs_int_t             ret;
    njs_str_t             s;
    njs_bool_t            success;
    njs_uint_t            i;
    njs_stat_t            prev;
    njs_vm_opt_t          options;
    njs_runtime_t         *rt;
    njs_opaque_value_t    retval;
    njs_external_state_t  *state;

    njs_str_t preload = njs_str(
        "globalThis.preload = JSON.parse("
            "'{\"a\": [1, {\"b\": 2, \"c\": 3}]}',"
            "function (k, v) {"
                "if (v instanceof Object) {"
                    "Object.freeze(Object.setPrototypeOf(v, null));"
                "}"
                "return v;"
            "}"
        ");"
    );

    vm = NULL;
    rt = NULL;

    prev = *stat;

    ret = NJS_ERROR;

    for (i = 0; i < num; i++) {

        if (opts->verbose) {
            njs_printf("\"%V\"\n", &tests[i].script);
        }

        njs_vm_opt_init(&options);

        options.init = opts->preload;
        options.module = opts->module;
        options.unsafe = opts->unsafe;
        options.backtrace = opts->backtrace;
        options.max_stack_size = 64 * 1024;
        options.addons = opts->externals ? njs_unit_test_addon_external_modules
                                         : njs_unit_test_addon_modules;

        vm = njs_vm_create(&options);
        if (vm == NULL) {
            njs_printf("njs_vm_create() failed\n");
            goto done;
        }

        njs_vm_set_module_loader(vm, njs_unit_test_module_loader, NULL);

        if (opts->preload) {
            start = preload.start;
            end = start + preload.length;

            ret = njs_vm_compile(vm, &start, end);
            if (ret != NJS_OK) {
                njs_printf("njs_vm_compile() preload failed\n");
                goto done;
            }

            ret = njs_vm_start(vm, njs_value_arg(&retval));
            if (ret != NJS_OK) {
                njs_printf("njs_vm_start() preload failed\n");
                goto done;
            }

            ret = njs_vm_reuse(vm);
            if (ret != NJS_OK) {
                njs_printf("njs_vm_reuse() failed\n");
                goto done;
            }
        }

        start = tests[i].script.start;
        end = start + tests[i].script.length;

        ret = njs_vm_compile(vm, &start, end);

        if (ret == NJS_OK && start == end) {
            if (opts->disassemble) {
                njs_disassembler(vm);
            }

            rt = njs_runtime_init(vm, opts);
            if (rt == NULL) {
                njs_stderror("njs_runtime_init() failed\n");
                goto done;
            }

            for ( ;; ) {
                state = njs_runtime_next_state(rt, opts);
                if (state == NULL) {
                    break;
                }

                ret = njs_process_test(state, opts, &tests[i]);
                if (ret != NJS_OK) {
                    if (ret == NJS_DECLINED) {
                        break;
                    }

                    njs_stderror("njs_process_test() failed\n");
                    goto done;
                }
            }

            success = (ret == NJS_OK);

            if (rt != NULL) {
                njs_runtime_destroy(rt);
                rt = NULL;
            }

